const now = new Date();
const dateStr = now.toISOString().replace(/[-:T]/g, '').substring(0, 14);
const randomSuffix = Math.random().toString(36).substring(2, 6);
const submissionId = `CPA-${dateStr}-${randomSuffix}`;

const trainerEmail = $input.first().json['Trainer Email'] || '';
const notes = $input.first().json['Notes'] || '';

const binaryKeys = Object.keys($input.first().binary || {});
if (binaryKeys.length === 0) throw new Error('No file uploaded');

const fileKey = binaryKeys[0];
const fileBinary = $input.first().binary[fileKey];
const mimeType = fileBinary.mimeType || '';
const fileName = fileBinary.fileName || 'unknown';

if (!mimeType.includes('application/pdf') && !mimeType.includes('image/')) {
  throw new Error(`Unsupported file type: ${mimeType}. Please upload a PDF, JPG, or PNG.`);
}

return [{
  json: { submissionId, trainerEmail, notes, mimeType, fileName, dateProcessed: now.toISOString() },
  binary: $input.first().binary
}];

const input = $input.first().json;
const prevData = $('Parse Upload + Generate ID').first().json;

let binaryData = {};
try {
  const parseNode = $('Parse Upload + Generate ID').first();
  if (parseNode.binary) binaryData = parseNode.binary;
} catch(e) {}
if (!binaryData || Object.keys(binaryData).length === 0) {
  try {
    const formNode = $('Upload Exam Form').first();
    if (formNode.binary) binaryData = formNode.binary;
  } catch(e) {}
}

let aiResponse;
let multiPageNote = '';

try {
  let responseText = '';

  if (input?.candidates?.[0]?.content?.parts?.[0]?.text) {
    responseText = input.candidates[0].content.parts[0].text;
  }
  else if (typeof input?.text === 'string' && input.text.length > 10) {
    responseText = input.text;
  }
  else if (typeof input?.content === 'string') {
    responseText = input.content;
  }
  else {
    const searchForJson = (obj, depth = 0) => {
      if (depth > 5) return '';
      if (typeof obj === 'string' && obj.includes('is_exam_form')) return obj;
      if (Array.isArray(obj)) {
        for (const item of obj) { const r = searchForJson(item, depth + 1); if (r) return r; }
      } else if (obj && typeof obj === 'object') {
        for (const val of Object.values(obj)) { const r = searchForJson(val, depth + 1); if (r) return r; }
      }
      return '';
    };
    responseText = searchForJson(input);
  }

  if (!responseText) throw new Error('Could not find Gemini response text. Keys: ' + Object.keys(input).join(', '));

  responseText = responseText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
  if (responseText.includes('\\n')) responseText = responseText.replace(/\\n/g, '\n');

  const jsonMatch = responseText.match(/(\[[\s\S]*\]|\{[\s\S]*\})/);
  if (!jsonMatch) throw new Error('No JSON found in response. First 200 chars: ' + responseText.substring(0, 200));

  const parsed = JSON.parse(jsonMatch[0]);
  if (Array.isArray(parsed)) {
    multiPageNote = `[Multi-page: ${parsed.length} students detected. Processing student 1 only. Full multi-student support in Phase 2.]`;
    aiResponse = parsed[0];
  } else {
    aiResponse = parsed;
  }

} catch (e) {
  return [{ json: { ...prevData, error: `Parse error: ${e.message}`, status: 'ERROR', overallConfidence: 0, missingFields: JSON.stringify(['all - parse error']), courseCode: '', courseName: '', studentFirstName: '', studentLastName: '', examDate: '', writtenGrade: '', passFail: '', studentSignature: '', trainerSignature: '', trainerName: '', ptiTrainerId: '', examAccessKey: '', handsOnComplete: false, notes: prevData.notes || '' }, binary: binaryData }];
}

if (!aiResponse.is_exam_form) {
  return [{ json: { ...prevData, is_exam_form: false, status: 'NOT_AN_EXAM', overallConfidence: 0, missingFields: JSON.stringify([]), courseCode: '', courseName: '', studentFirstName: '', studentLastName: '', examDate: '', writtenGrade: '', passFail: '', studentSignature: '', trainerSignature: '', trainerName: '', ptiTrainerId: '', examAccessKey: '', handsOnComplete: false, notes: prevData.notes || '' }, binary: binaryData }];
}

const getVal = (f) => f && typeof f === 'object' ? f.value : f;
const getConf = (f) => f && typeof f === 'object' ? (f.confidence || 0) : 0.5;
const getNotes = (f) => f && typeof f === 'object' ? (f.notes || '') : '';

const fields = {
  examDate: { val: getVal(aiResponse.exam_date), conf: getConf(aiResponse.exam_date), notes: getNotes(aiResponse.exam_date), weight: 1.0 },
  studentFirstName: { val: getVal(aiResponse.student_first_name), conf: getConf(aiResponse.student_first_name), notes: getNotes(aiResponse.student_first_name), weight: 1.0 },
  studentLastName: { val: getVal(aiResponse.student_last_name), conf: getConf(aiResponse.student_last_name), notes: getNotes(aiResponse.student_last_name), weight: 1.0 },
  studentSignature: { val: getVal(aiResponse.student_signature), conf: getConf(aiResponse.student_signature), notes: getNotes(aiResponse.student_signature), weight: 0.5 },
  writtenGrade: { val: getVal(aiResponse.written_grade), conf: getConf(aiResponse.written_grade), notes: getNotes(aiResponse.written_grade), weight: 1.0 },
  trainerSignature: { val: getVal(aiResponse.trainer_signature), conf: getConf(aiResponse.trainer_signature), notes: getNotes(aiResponse.trainer_signature), weight: 0.5 },
  trainerName: { val: getVal(aiResponse.trainer_name), conf: getConf(aiResponse.trainer_name), notes: getNotes(aiResponse.trainer_name), weight: 1.0 },
  ptiTrainerId: { val: getVal(aiResponse.pti_trainer_id), conf: getConf(aiResponse.pti_trainer_id), notes: getNotes(aiResponse.pti_trainer_id), weight: 1.5 },
  examAccessKey: { val: getVal(aiResponse.exam_access_key), conf: getConf(aiResponse.exam_access_key), notes: getNotes(aiResponse.exam_access_key), weight: 1.5 },
  handsOnComplete: { val: aiResponse.hands_on_tasks?.all_mandatory_passed, conf: aiResponse.hands_on_tasks?.confidence || 0.5, notes: aiResponse.hands_on_tasks?.notes || '', weight: 1.0 }
};

for (const [key, field] of Object.entries(fields)) {
  if (['ptiTrainerId', 'examAccessKey'].includes(key) && field.notes && (field.notes.toLowerCase().includes('ambiguous') || field.notes.toLowerCase().includes('unclear'))) {
    field.conf = Math.max(0, field.conf - 0.1);
  }
  if (['studentFirstName', 'studentLastName', 'trainerName'].includes(key) && field.notes && (field.notes.toLowerCase().includes('unclear') || field.notes.toLowerCase().includes('smudged'))) {
    field.conf = Math.max(0, field.conf - 0.05);
  }
  if (key === 'examDate' && field.notes && field.notes.toLowerCase().includes('ambig')) {
    field.conf = Math.max(0, field.conf - 0.1);
  }
}

let totalWeight = 0, weightedSum = 0;
for (const field of Object.values(fields)) { totalWeight += field.weight; weightedSum += field.conf * field.weight; }
const overallConfidence = totalWeight > 0 ? Math.round((weightedSum / totalWeight) * 100) / 100 : 0;

const missingFields = [];
if (!fields.examDate.val) missingFields.push('examDate');
if (!fields.studentFirstName.val) missingFields.push('studentFirstName');
if (!fields.studentLastName.val) missingFields.push('studentLastName');
if (fields.studentSignature.val === 'ABSENT' || !fields.studentSignature.val) missingFields.push('studentSignature');
if (!fields.writtenGrade.val && fields.writtenGrade.val !== 0) missingFields.push('writtenGrade');
if (fields.trainerSignature.val === 'ABSENT' || !fields.trainerSignature.val) missingFields.push('trainerSignature');
if (!fields.trainerName.val) missingFields.push('trainerName');
if (!fields.ptiTrainerId.val) missingFields.push('ptiTrainerId');
if (!fields.examAccessKey.val) missingFields.push('examAccessKey');
if (fields.handsOnComplete.val !== true) missingFields.push('handsOnTasks');

let status;
if (missingFields.length > 0) { status = 'INCOMPLETE'; }
else if (overallConfidence >= 0.90) { status = 'READY_FOR_CRM'; }
else if (overallConfidence >= 0.75) { status = 'NEEDS_REVIEW'; }
else { status = 'INCOMPLETE'; }

const grade = parseFloat(fields.writtenGrade.val);
const threshold = parseFloat(aiResponse.passing_threshold) || 75;
let passFail = 'UNKNOWN';
if (!isNaN(grade)) passFail = grade >= threshold ? 'PASS' : 'FAIL';

const allNotes = Object.entries(fields).filter(([k, f]) => f.notes).map(([k, f]) => `${k}: ${f.notes}`).join('; ');
const combinedNotes = [prevData.notes, multiPageNote, allNotes].filter(Boolean).join(' | ');

return [{
  json: {
    submissionId: prevData.submissionId,
    dateProcessed: prevData.dateProcessed,
    trainerEmail: prevData.trainerEmail,
    courseCode: aiResponse.course_code || '',
    courseName: aiResponse.course_name || '',
    studentFirstName: fields.studentFirstName.val || '',
    studentLastName: fields.studentLastName.val || '',
    examDate: fields.examDate.val || '',
    writtenGrade: fields.writtenGrade.val || '',
    passFail,
    studentSignature: fields.studentSignature.val || '',
    trainerSignature: fields.trainerSignature.val || '',
    trainerName: fields.trainerName.val || '',
    ptiTrainerId: fields.ptiTrainerId.val || '',
    examAccessKey: fields.examAccessKey.val || '',
    handsOnComplete: fields.handsOnComplete.val === true,
    overallConfidence,
    status,
    missingFields: JSON.stringify(missingFields),
    notes: combinedNotes,
    fileName: prevData.fileName
  },
  binary: binaryData
}];
